fun solve(s: String): Long {
    val n = s.length
    var totalL = 0L
    var totalC = 0L
    var totalT = 0L
    val prefixL = LongArray(n + 1)
    val suffixT = LongArray(n + 1)

    // Compute prefixL: prefixL[i] is the number of 'L's in s[0..i-1]
    for (i in 1..n) {
        prefixL[i] = prefixL[i - 1] + if (s[i - 1] == 'L') 1 else 0
    }
    totalL = prefixL[n]

    // Compute suffixT: suffixT[i] is the number of 'T's in s[i..n-1]
    for (i in n - 1 downTo 0) {
        suffixT[i] = suffixT[i + 1] + if (s[i] == 'T') 1 else 0
    }
    totalT = suffixT[0]

    // Compute totalC: number of 'C's in s
    for (c in s) {
        if (c == 'C') totalC++
    }

    // Compute the original count without any insertion
    var originalCount = 0L
    for (i in s.indices) {
        if (s[i] == 'C') {
            originalCount += prefixL[i] * suffixT[i + 1]
        }
    }

    if (totalL == 0L || totalC == 0L || totalT == 0L) {
        // If any of L, C, T is missing, inserting one can't help
        return originalCount
    }

    var maxCount = originalCount

    // Case 1: Insert 'L' at position i (new 'L' is at i)
    // The new 'L' contributes to prefixL[i+1..n], and can pair with any 'C' after it and 'T' after that 'C'
    var bestL = 0L
    var sumCAfter = 0L
    var sumTAfterC = 0L
    for (i in n downTo 0) {
        if (i < n && s[i] == 'C') {
            sumCAfter++
            sumTAfterC += suffixT[i + 1]
        }
        bestL = maxOf(bestL, sumTAfterC)
    }
    maxCount = maxOf(maxCount, originalCount + bestL)

    // Case 2: Insert 'C' at position i (new 'C' is at i)
    // The new 'C' contributes prefixL[i] * suffixT[i]
    var bestC = 0L
    for (i in 0..n) {
        val l = prefixL[i]
        val t = suffixT[i]
        bestC = maxOf(bestC, l * t)
    }
    maxCount = maxOf(maxCount, originalCount + bestC)

    // Case 3: Insert 'T' at position i (new 'T' is at i)
    // The new 'T' can be paired with any 'C' before it and 'L' before that 'C'
    var bestT = 0L
    var sumCBefore = 0L
    var sumLBeforeC = 0L
    for (i in 0..n) {
        if (i > 0 && s[i - 1] == 'C') {
            sumCBefore++
            sumLBeforeC += prefixL[i - 1]
        }
        bestT = maxOf(bestT, sumLBeforeC)
    }
    maxCount = maxOf(maxCount, originalCount + bestT)

    return maxCount
}
